import React, { useState, useEffect } from 'react';
import { useLocation, useParams, useNavigate } from 'react-router-dom';

const StudySession = () => {
  const { day } = useParams();
  const { state } = useLocation(); // Gets the topic passed from Dashboard
  const navigate = useNavigate();

  // Timer States (Default 30 minutes = 1800 seconds)
  const [timeLeft, setTimeLeft] = useState(1800);
  const [isActive, setIsActive] = useState(false);
  
  // AI & Completion States
  const [sessionStatus, setSessionStatus] = useState(null); // 'completed' or 'missed'
  const [showAIField, setShowAIField] = useState(false);
  const [userAnswer, setUserAnswer] = useState('');

  // 1. Timer Logic
  useEffect(() => {
    let interval = null;
    if (isActive && timeLeft > 0) {
      interval = setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    } else if (timeLeft === 0) {
      clearInterval(interval);
      setIsActive(false);
      handleFinish('completed'); // Auto-complete if time runs out
    }
    return () => clearInterval(interval);
  }, [isActive, timeLeft]);

  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs < 10 ? '0' : ''}${secs}`;
  };

  // 2. Handling Completion
  const handleFinish = (status) => {
    setSessionStatus(status);
    setIsActive(false);
    setShowAIField(true);
  };

  const submitToAI = () => {
    // Here you would send 'userAnswer' to your backend/Gemini API
    alert(`Session for ${state?.topic} saved as ${sessionStatus}!`);
    navigate('/dashboard');
  };

  return (
    <div style={{ padding: '40px', fontFamily: 'Arial', textAlign: 'center', backgroundColor: '#f4f7f6', minHeight: '100vh' }}>
      <div style={{ maxWidth: '600px', margin: '0 auto', background: 'white', padding: '30px', borderRadius: '15px', boxShadow: '0 10px 25px rgba(0,0,0,0.1)' }}>
        
        <button onClick={() => navigate('/dashboard')} style={{ float: 'left', border: 'none', background: 'none', cursor: 'pointer', color: '#3498db' }}>← Back</button>
        
        <h2 style={{ color: '#2c3e50' }}>Day {day}: {state?.topic || "Study Session"}</h2>
        <hr />

        {/* Timer Display */}
        <div style={{ fontSize: '64px', margin: '30px 0', fontWeight: 'bold', color: timeLeft < 300 ? '#e74c3c' : '#2c3e50' }}>
          {formatTime(timeLeft)}
        </div>

        {!showAIField ? (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
            <button 
              onClick={() => setIsActive(!isActive)}
              style={{ padding: '15px', fontSize: '18px', borderRadius: '8px', border: 'none', backgroundColor: isActive ? '#f1c40f' : '#2ecc71', color: 'white', cursor: 'pointer' }}
            >
              {isActive ? 'Pause Focus' : 'Start Focus Timer'}
            </button>

            <div style={{ display: 'flex', gap: '10px', marginTop: '20px' }}>
              <button 
                onClick={() => handleFinish('completed')}
                style={{ flex: 1, padding: '12px', borderRadius: '8px', border: 'none', backgroundColor: '#3498db', color: 'white', cursor: 'pointer' }}
              >
                Successfully Completed
              </button>
              <button 
                onClick={() => handleFinish('missed')}
                style={{ flex: 1, padding: '12px', borderRadius: '8px', border: 'none', backgroundColor: '#95a5a6', color: 'white', cursor: 'pointer' }}
              >
                Missed/Incomplete
              </button>
            </div>
          </div>
        ) : (
          /* AI Question Section */
          <div style={{ marginTop: '20px', textAlign: 'left', animation: 'fadeIn 0.5s' }}>
            <div style={{ padding: '15px', backgroundColor: '#ebf5fb', borderRadius: '8px', marginBottom: '15px' }}>
              <strong>AI Tutor:</strong> "Great effort! To confirm your understanding of <strong>{state?.topic}</strong>, can you explain the core concept in your own words?"
            </div>
            
            <textarea 
              value={userAnswer}
              onChange={(e) => setUserAnswer(e.target.value)}
              placeholder="Type your explanation here..."
              style={{ width: '100%', height: '120px', padding: '10px', borderRadius: '8px', border: '1px solid #ddd', marginBottom: '15px' }}
            />

            <button 
              onClick={submitToAI}
              style={{ width: '100%', padding: '15px', borderRadius: '8px', border: 'none', backgroundColor: '#2c3e50', color: 'white', cursor: 'pointer', fontWeight: 'bold' }}
            >
              Submit & Finish Day
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default StudySession;
